import { NextRequest } from 'next/server'

export const runtime = 'edge'

export interface BrainState {
  adccl: number
  provider: number
  threat: number
  phylactery: number
  ledger: number
  alignment: number
  stage: string
}

const IDLE_STATE: BrainState = {
  adccl: 0.05,
  provider: 0.05,
  threat: 0.02,
  phylactery: 0.08,
  ledger: 0.02,
  alignment: 0.05,
  stage: 'idle',
}

// Module-level shared state store keyed by session ID
const stateStore = new Map<string, BrainState>()

export function setBrainState(session: string, state: Partial<BrainState>): void {
  const current = stateStore.get(session) ?? { ...IDLE_STATE }
  stateStore.set(session, { ...current, ...state })
}

export async function GET(req: NextRequest) {
  const session = req.nextUrl.searchParams.get('session') ?? 'global'
  const encoder = new TextEncoder()

  const stream = new ReadableStream({
    async start(controller) {
      let lastJson = ''
      const maxTicks = 60
      let tick = 0

      while (tick < maxTicks) {
        const state = stateStore.get(session) ?? { ...IDLE_STATE }
        const json = JSON.stringify(state)

        if (json !== lastJson) {
          controller.enqueue(encoder.encode(`data: ${json}\n\n`))
          lastJson = json
        } else {
          // keepalive comment
          controller.enqueue(encoder.encode(':\n\n'))
        }

        tick++
        await new Promise((r) => setTimeout(r, 500))
      }

      controller.close()
    },
  })

  return new Response(stream, {
    headers: {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      Connection: 'keep-alive',
    },
  })
}

